package net.minecraft.client.entity; import java.util.Collection; import java.util.Collections; import net.minecraft.entity.Entity; import net.minecraft.entity.player.EntityPlayer; import net.minecraft.entity.player.FoodStats; import net.minecraft.potion.PotionEffect; public class EntityPlayerSP extends EntityPlayer { public boolean isCollidedHorizontally,isCollidedVertically; public float fallDistance; private final FoodStats food=new FoodStats(); public float getAbsorptionAmount(){return 0;} public FoodStats getFoodStats(){return food;} public boolean isInWater(){return false;} public boolean isInLava(){return false;} public boolean isOnLadder(){return false;} public boolean isEntityInsideOpaqueBlock(){return false;} public boolean isUsingItem(){return false;} public Collection<PotionEffect> getActivePotionEffects(){return Collections.emptyList();} public boolean canEntityBeSeen(Entity e){return true;} public float getDistanceToEntity(Entity e){double dx=e.posX-posX,dy=e.posY-posY,dz=e.posZ-posZ;return (float)Math.sqrt(dx*dx+dy*dy+dz*dz);} }
